import { useEffect, useState } from "react";
import API_URL from "../api";
import { FaLock, FaClock, FaHeart, FaBook } from "react-icons/fa"; // Import icons

function Home() {
  const [capsules, setCapsules] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchCapsules = async () => {
      try {
        const token = localStorage.getItem("token");
        const response = await fetch(`${API_URL}/api/memoryhaven`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        if (!response.ok) throw new Error("Failed to fetch capsules.");

        const data = await response.json();
        setCapsules(data);
      } catch (error) {
        console.error("Error fetching capsules:", error);
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };

    fetchCapsules();
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-b from-pink-100 to-blue-100 py-12 px-6">
      {/* Hero Section */}
      <div className="text-center mb-10">
        <h1 className="text-5xl font-extrabold text-gray-900 animate-fade-in">
          Memory Haven
        </h1>
        <p className="text-lg text-gray-700 mt-3">
          Save your memories today and relive them in the future!
        </p>
      </div>

      {/* About Section */}
      <section className="max-w-4xl mx-auto bg-white p-6 rounded-lg shadow-lg transition hover:shadow-2xl">
        <h2 className="text-3xl font-bold text-gray-800">About Memory Haven</h2>
        <p className="text-gray-700 mt-2 leading-relaxed">
          Memory Haven allows you to store memories, messages, and media capsules that unlock 
          at a future date. Whether it’s a heartfelt letter, a surprise video, or a personal 
          time capsule, we ensure your moments are preserved securely.
        </p>
      </section>

      {/* How It Works */}
      <section className="max-w-4xl mx-auto bg-white p-6 rounded-lg shadow-lg mt-10 transition hover:shadow-2xl">
        <h2 className="text-3xl font-bold text-gray-800">How It Works</h2>
        <ul className="list-decimal list-inside text-gray-700 mt-3 leading-relaxed">
          <li>Sign up and create your secure account.</li>
          <li>Upload memories in the form of text, images, or videos.</li>
          <li>Set an unlock date for your capsule.</li>
          <li>Revisit your memories when the time arrives.</li>
        </ul>
      </section>

      {/* Why Use Memory Haven */}
      <section className="max-w-4xl mx-auto bg-white p-6 rounded-lg shadow-lg mt-10 transition hover:shadow-2xl">
        <h2 className="text-3xl font-bold text-gray-800 text-center mb-4">Why Use Memory Haven?</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 text-center">
          <div className="p-4 bg-gray-100 rounded-lg hover:bg-gray-200 transition">
            <FaLock className="text-blue-600 text-3xl mx-auto" />
            <p className="mt-2 text-gray-700">Secure storage for your memories.</p>
          </div>
          <div className="p-4 bg-gray-100 rounded-lg hover:bg-gray-200 transition">
            <FaBook className="text-green-600 text-3xl mx-auto" />
            <p className="mt-2 text-gray-700">Perfect for personal growth tracking.</p>
          </div>
          <div className="p-4 bg-gray-100 rounded-lg hover:bg-gray-200 transition">
            <FaHeart className="text-red-600 text-3xl mx-auto" />
            <p className="mt-2 text-gray-700">Great for surprises & special moments.</p>
          </div>
          <div className="p-4 bg-gray-100 rounded-lg hover:bg-gray-200 transition">
            <FaClock className="text-purple-600 text-3xl mx-auto" />
            <p className="mt-2 text-gray-700">Easy access to past emotions.</p>
          </div>
        </div>
      </section>

      {/* Recent Capsules */}
      <h2 className="text-3xl font-bold text-gray-800 text-center mt-12 mb-6">
        Recent Capsules
      </h2>

      {loading ? (
        <p className="text-center text-gray-700">Loading capsules...</p>
      ) : error ? (
        <p className="text-center text-red-500">Error: {error}</p>
      ) : capsules.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 max-w-6xl mx-auto">
          {capsules.map((capsule) => (
            <div
              key={capsule._id}
              className="bg-white p-5 rounded-lg shadow-lg hover:shadow-xl transition duration-300"
            >
              <h3 className="text-2xl font-semibold text-gray-800">{capsule.title}</h3>
              <p className="text-gray-600 mt-2">{capsule.description}</p>
              <p className="text-sm text-gray-500 mt-2">
                Unlocks on: <span className="font-medium">{new Date(capsule.unlockDate).toDateString()}</span>
              </p>
            </div>
          ))}
        </div>
      ) : (
        <p className="text-center text-gray-600">No capsules found. Create one now!</p>
      )}
    </div>
  );
}

export default Home;
